INSERT INTO announcements (announcement_id, school_id, title, message, type, status, priority, target_audience, pinned, author_user_id, publish_date, expiry_date, is_deleted, created_at, updated_at) VALUES
  (1, 1, 'Welcome to Term 2 2026', 'We are excited to welcome all students and staff back for Term 2 2026. Classes begin on Monday, May 3rd. Please ensure all students report to school on time with complete uniforms and learning materials.', 'general', 'published', 'high', 'all', TRUE, 100, '2026-05-01T08:00:00+00:00', '2026-05-31T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (2, 1, 'Parent-Teacher Meeting', 'All parents are invited to attend the Parent-Teacher Meeting scheduled for Friday, May 21st at 2:00 PM in the school hall. We will discuss student progress and upcoming school activities.', 'event', 'published', 'normal', 'all', FALSE, 100, '2026-05-10T09:00:00+00:00', '2026-05-20T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (3, 1, 'Mid-Term Examination Schedule', 'Mid-term examinations will commence on June 10th and conclude on June 14th. Students are advised to prepare adequately. The examination timetable has been posted on the notice board.', 'academic', 'published', 'high', 'all', TRUE, 100, '2026-05-15T10:00:00+00:00', '2026-06-15T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (4, 1, 'School Holiday Notice', 'The school will be closed for the mid-term break from June 15th to June 20th. Classes resume on June 21st. Parents are requested to ensure students return on time.', 'general', 'published', 'normal', 'all', FALSE, 100, '2026-05-20T11:00:00+00:00', '2026-06-20T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (5, 1, 'Sports Day Preparation', 'Our annual sports day will be held on July 5th. All students are required to participate. House captains should start preparing their teams. Practice sessions will be held every afternoon from 3:00 PM.', 'event', 'published', 'normal', 'all', FALSE, 100, '2026-05-25T12:00:00+00:00', '2026-07-05T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (6, 1, 'Staff Meeting - Curriculum Review', 'All teaching staff are required to attend a curriculum review meeting on Wednesday, May 26th at 3:30 PM in the staff room. Please bring your subject files and assessment records.', 'academic', 'published', 'normal', 'teachers', FALSE, 100, '2026-05-18T14:00:00+00:00', '2026-05-26T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (7, 1, 'Fee Payment Reminder', 'This is a reminder to all parents that Term 2 fees are due by May 30th. Late payments will attract a penalty. Please contact the finance office for any payment arrangements.', 'general', 'published', 'high', 'parents', TRUE, 100, '2026-05-12T08:00:00+00:00', '2026-05-30T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00'),
  (8, 1, 'Library Books Return', 'All students must return library books borrowed during Term 1 by May 15th. Failure to return books will result in a fine and restriction of borrowing privileges.', 'academic', 'published', 'normal', 'students', FALSE, 100, '2026-05-05T09:00:00+00:00', '2026-05-15T23:59:59+00:00', FALSE, '2026-05-17T21:14:19.584066+00:00', '2026-05-17T21:14:19.584066+00:00');
